32.             .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel", "PredictedLabel"));
33. 
34.         // Cross-validate and log metrics
35.         var cvResults = mlContext.MulticlassClassification.CrossValidate(data, pipeline, numberOfFolds: 5, labelColumnName: "Label");
