 using System.ComponentModel.DataAnnotations;
 using Microsoft.AspNetCore.Mvc;
 using Microsoft.Extensions.ML;
 using TicketClassifier.Models;

 namespace TicketClassifier.Controllers;

 public class TicketPredictionRequest
 {
     [Required]
     public string Subject { get; set; } = string.Empty;

     [Required]
     public string Description { get; set; } = string.Empty;

     [Required]
     [Range(1, 3)]
     public int Priority { get; set; }
 }

 public class TicketPredictionResponse
 {
     public string Category { get; set; } = string.Empty;
     public float Confidence { get; set; }
     public Dictionary<string, float> Scores { get; set; } = new();
 }

 [ApiController]
 [Route("api/[controller]")]
 public class PredictController : ControllerBase
 {
     private static readonly string[] Categories = ["Billing", "General", "Technical"];
     private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;

     public PredictController(PredictionEnginePool<TicketInput, TicketPrediction> pool)
     {
         _pool = pool;
     }

     [HttpPost]
     public ActionResult<TicketPredictionResponse> Predict([FromBody] TicketPredictionRequest request)
     {
         var input = new TicketInput
         {
             Subject = request.Subject,
             Description = request.Description,
             Priority = request.Priority
         };

         var prediction = _pool.Predict(input);

         var scores = new Dictionary<string, float>();
         for (var i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
         {
             scores[Categories[i]] = prediction.Score[i];
         }

         return Ok(new TicketPredictionResponse
         {
             Category = prediction.Category,
             Confidence = prediction.Score.Max(),
             Scores = scores
         });
     }
 }

