using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService : IHostedService
{
    private readonly ILogger<ModelTrainingService> _logger;
    private readonly ModelMetadata _metadata;

    public ModelTrainingService(ILogger<ModelTrainingService> logger, ModelMetadata metadata)
    {
        _logger = logger;
        _metadata = metadata;
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath,
            hasHeader: true,
            separatorChar: ',',
            allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", "Category")
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", "Subject"))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", "Description"))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", "Priority"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel", "PredictedLabel"));

        // Cross-validate and log metrics
        var cvResults = mlContext.MulticlassClassification.CrossValidate(data, pipeline, numberOfFolds: 5, labelColumnName: "Label");
        foreach (var (result, index) in cvResults.Select((r, i) => (r, i)))
        {
            _logger.LogInformation(
                "Fold {Fold}: MacroAccuracy={MacroAccuracy:F4}, MicroAccuracy={MicroAccuracy:F4}, LogLoss={LogLoss:F4}",
                index + 1,
                result.Metrics.MacroAccuracy,
                result.Metrics.MicroAccuracy,
                result.Metrics.LogLoss);
        }

        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgLogLoss = cvResults.Average(r => r.Metrics.LogLoss);
        _logger.LogInformation(
            "Average: MacroAccuracy={MacroAccuracy:F4}, MicroAccuracy={MicroAccuracy:F4}, LogLoss={LogLoss:F4}",
            avgMacro, avgMicro, avgLogLoss);

        // Train on full dataset and extract label ordering from the model
        var model = pipeline.Fit(data);

        using var predEngine = mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(model);
        var scoreColumn = predEngine.OutputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.Annotations.GetValue("SlotNames", ref slotNames);
        _metadata.Labels = slotNames.DenseValues().Select(x => x.ToString()).ToArray();
        _logger.LogInformation("Label ordering: {Labels}", string.Join(", ", _metadata.Labels));

        // Save model
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

